import java.util.*;

public class SetExample {
    public static void main(String[] args) {
        // HashSet — no duplicates, no order
        System.out.println("=== HashSet ===");
        HashSet<String> hashSet = new HashSet<>();

        hashSet.add("Apple");
        hashSet.add("Banana");
        hashSet.add("Orange");
        hashSet.add("Apple");  // Duplicate — ignored!
        hashSet.add("Grape");
        hashSet.add("Banana");  // Duplicate — ignored!

        System.out.println("HashSet: " + hashSet);  // No guaranteed order
        System.out.println("Size: " + hashSet.size());  // 4 (not 6)

        // TreeSet — sorted order, no duplicates
        System.out.println("=== TreeSet ===");
        TreeSet<String> treeSet = new TreeSet<>();

        treeSet.add("Apple");
        treeSet.add("Banana");
        treeSet.add("Orange");
        treeSet.add("Apple");  // Duplicate — ignored!
        treeSet.add("Grape");

        System.out.println("TreeSet: " + treeSet);  // Sorted alphabetically
        System.out.println("Size: " + treeSet.size());  // 4

        // HashSet operations
        System.out.println("=== HashSet Operations ===");
        System.out.println("Contains 'Apple'? " + hashSet.contains("Apple"));
        System.out.println("Contains 'Mango'? " + hashSet.contains("Mango"));

        hashSet.remove("Grape");
        System.out.println("After removing Grape: " + hashSet);

        // TreeSet operations
        System.out.println("=== TreeSet Operations ===");
        System.out.println("First: " + treeSet.first());  // Smallest
        System.out.println("Last: " + treeSet.last());   // Largest
        System.out.println("Lower than 'Grape': " + treeSet.lower("Grape"));
        System.out.println("Higher than 'Grape': " + treeSet.higher("Grape"));

        // Performance comparison
        System.out.println("=== Performance ===");
        // HashSet: O(1) average for add/contains/remove
        // TreeSet: O(log n) for add/contains/remove

        // Removing duplicates from a list
        System.out.println("=== Remove Duplicates ===");
        ArrayList<String> withDuplicates = new ArrayList<>(
            Arrays.asList("A", "B", "A", "C", "B", "D", "A")
        );
        System.out.println("With duplicates: " + withDuplicates);

        HashSet<String> unique = new HashSet<>(withDuplicates);
        System.out.println("Without duplicates: " + unique);

        // Converting back to list
        ArrayList<String> uniqueList = new ArrayList<>(unique);
        System.out.println("As list: " + uniqueList);

        // Set with custom objects
        System.out.println("=== Custom Objects ===");
        HashSet<Person> people = new HashSet<>();
        people.add(new Person("Alice", 25));
        people.add(new Person("Bob", 30));
        people.add(new Person("Alice", 25));  // Duplicate (if equals/hashCode implemented)

        System.out.println("People size: " + people.size());
        for (Person p : people) {
            System.out.println("  " + p);
        }
    }
}

class Person {
    String name;
    int age;

    Person(String name, int age) {
        this.name = name;
        this.age = age;
    }

    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (o == null || getClass() != o.getClass()) return false;
        Person person = (Person) o;
        return age == person.age && Objects.equals(name, person.name);
    }

    @Override
    public int hashCode() {
        return Objects.hash(name, age);
    }

    @Override
    public String toString() {
        return "Person{name='" + name + "', age=" + age + "}";
    }
}

